```javascript
function _syncPagination(totalCount) {
  if (!_paginationEl) return;
  const pages    = Math.ceil(totalCount / s.perPage) || 1;
  const current  = clamp(s.page, 1, pages);
  const text     = pages > 1 ? `Page ${current} of ${pages}` : '';
  _paginationEl.textContent = text;
  _paginationEl.setAttribute('aria-label', text);
  // Announce change
  liveRegion.announce(`Page ${current} of ${pages}`);
}
```

